INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('M2_L4_B', 'M2', 4, 'B', 'Design and Justification', NULL, 'Say: ''I will give you an equation: 4 + 4 + 4 + 4 = 16. Write a short story about building something that uses this equation. Then draw a diagram of what you built.''', 'Child invents a story involving four sides of equal length (like a square fence) or four groups of four items, and draws a matching model.', 'Child just writes an abstract story (''I had 4 numbers and added them'') without a real-world object or diagram.', 'If you changed your story to be about a triangle, what would the equation look like?', '{"default":{"objects":["blocks","tiles","cards"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["stones","bottle caps","sticks"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('M2_L4_C', 'M2', 4, 'C', 'Design and Justification', NULL, 'Say: ''Design a simple map of a small park with a path running through it. Write down a set of instructions using steps and directions (left/right) so someone can walk the path. Then, write an equation to show how many total steps long the path is.''', 'Child draws a map, writes clear directional instructions (e.g., ''Walk 10 steps, turn right, walk 5 steps''), and provides the correct total sum.', 'Child''s instructions don''t match the map, or the equation is missing/incorrect.', 'If I walked the path backwards, would the total number of steps be the same? Why?', '{"default":{"objects":["blocks","tiles","cards"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["stones","bottle caps","sticks"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('M2_L4_M', 'M2', 4, 'M', 'Real-world situation', NULL, 'We need to buy new tiles to cover the bathroom floor completely. We don''t want to buy too many, and we don''t want to run out. What exactly do you need to do to figure out how many tiles to buy?', 'Child describes a process of modeling the area: counting how many tiles fit along the length and width, and multiplying them (or drawing a grid to count the total).', 'Child suggests guessing, or just measuring one side.', 'If you know the floor is 6 tiles long and 5 tiles wide, why do you multiply them instead of adding 6 and 5?', '{"default":{"objects":["blocks","tiles","cards"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["stones","bottle caps","sticks"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);

-- File: english_band_2_strand_1.json
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('PS2a_L1_A', 'PS2a', 1, 'A', 'Auditory Discrimination', 'None', 'I am going to say three words. Two words have the same middle sound, but one is different. Listen: ''bat'', ''cat'', ''bit''. Which word sounds different in the middle?', 'Child correctly identifies ''bit''.', 'If wrong, stretch the words: ''b-aaaa-t'', ''c-aaaa-t'', ''b-iiii-t''. Ask them to try again.', 'What sound did you hear in the middle of ''bat''? What about ''bit''?', '{"default":{"words":[["bat","cat","bit"],["hop","mop","cup"],["sit","fit","set"]]},"ug":{"words":[["pan","fan","pin"],["pot","hot","hut"],["tin","bin","ten"]]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('PS2a_L1_B', 'PS2a', 1, 'B', 'Physical Sorting', '5 small containers or drawn circles, Small objects or drawn pictures representing short vowel CVC words (e.g., pen, pin, pot, pan, cup)', 'We have 5 boxes, one for each short vowel sound: /a/, /e/, /i/, /o/, /u/. Pick up an object, say its name, and put it in the box with the matching middle sound.', 'Child sorts the objects into the correct vowel categories.', 'If wrong, ask them to say the word slowly and isolate the middle sound.', 'Why did you put the ''pen'' in that box? What sound is in the middle?', '{"default":{"objects":["pen","pin","pot","pan","cup"]},"ug":{"objects":["tin","pot","pan","cup","bed"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('PS2a_L1_C', 'PS2a', 1, 'C', 'Verbal Substitution', 'None', 'Say the word ''mat''. Now, change the /a/ sound in the middle to an /o/ sound. What is the new word?', 'Child successfully produces the new word (''mot'' or similar, depending on prompt). Focus is on sound manipulation, not real words necessarily.', 'If incorrect, say the sounds individually: /m/ /a/ /t/, now /m/ /o/ /t/. Blend them for the child.', 'How did the word change when we swapped the middle sound?', '{"default":{"prompts":[["mat","/o/","mot"],["sit","/e/","set"]]},"ug":{"prompts":[["pan","/i/","pin"],["pot","/u/","put"]]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('PS2a_L2_A', 'PS2a', 2, 'A', 'Oral->Written Dictation', 'Paper, Pencil', 'I will say a word. You will say the sounds you hear, and then write the letters. The word is ''dog''.', 'Child says /d/ /o/ /g/ and writes ''dog''.', 'If spelled wrong, point to the incorrect letter and ask: ''What sound does this letter make? Does that match the word we want?''', 'How did you know which vowel to use in the middle?', '{"default":{"words":["dog","cat","pig","sun","hen"]},"ug":{"words":["cat","dog","pig","sun","hen"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('PS2a_L2_B', 'PS2a', 2, 'B', 'Oral->Written Word Building', 'Paper, Pencil', 'Let''s build a word ladder. Start by writing the word ''sit''. Read it aloud. Now change one letter to make it say ''sat''. Say the word, then write it.', 'Child writes ''sit'', says ''sat'', then writes ''sat''.', 'If they change the wrong letter, have them point to each letter and sound out what they wrote.', 'Which part of the word did you change? Why?', '{"default":{"ladders":[["sit","sat","mat","map"],["pin","pan","pat","pot"]]},"ug":{"ladders":[["pin","pan","pat","pot"],["tin","tan","tap","top"]]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('PS2a_L2_C', 'PS2a', 2, 'C', 'Oral->Written Sentence Dictation', 'Paper, Pencil', 'I will read a short sentence. Repeat it back to me, then write it down. ''The big pig sat in the mud.''', 'Child repeats the sentence correctly and writes it with mostly accurate phonetic spelling for CVC words.', 'If they miss words, repeat the sentence. If CVC words are misspelled, guide them to sound it out.', 'Read the sentence back to me. Did you include all the words?', '{"default":{"sentences":["The big pig sat in the mud.","A red bug is on the rug."]},"ug":{"sentences":["The big pig sat in the mud.","A red bug is on the mat."]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('PS2a_L3_A', 'PS2a', 3, 'A', 'Error Detection', 'Paper with printed sentence', 'Look at this sentence: ''The c-o-t ran after the mouse.'' There is a spelling mistake that changes the meaning. Find the mistake and fix it.', 'Child identifies ''cot'' as incorrect and changes it to ''cat''.', 'If they can''t find it, ask them to read the sentence aloud exactly as it is written.', 'Why doesn''t ''cot'' make sense in this sentence? What is the correct word?', '{"default":{"sentences":[{"text":"The c-o-t ran after the mouse.","error":"cot","fix":"cat"}]},"ug":{"sentences":[{"text":"The c-o-t ran after the rat.","error":"cot","fix":"cat"}]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('PS2a_L3_B', 'PS2a', 3, 'B', 'Auditory Error Detection', 'None', 'I''m going to say a sentence, but I will make a mistake with one of the words. Listen: ''I used a p-e-n to hold the papers together.'' Did I say that right?', 'Child identifies that ''pen'' is the wrong word and suggests ''pin''.', 'If they miss it, repeat the sentence emphasizing the incorrect word.', 'What does a ''pen'' do? What did I actually need?', '{"default":{"sentences":[{"text":"I used a p-e-n to hold the papers together.","error":"pen","fix":"pin"}]},"ug":{"sentences":[{"text":"I used a p-e-n to hold the cloth together.","error":"pen","fix":"pin"}]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('PS2a_L3_C', 'PS2a', 3, 'C', 'Nonsense Word Reading', 'Paper with printed words', 'Here is a list of words. Some are real words, and some are nonsense (silly) words. Read each one and tell me if it is real or nonsense: ''bim'', ''cat'', ''zug'', ''mop''.', 'Child correctly reads the words and categorizes them.', 'If they misread a word, ask them to point to each letter and say the sound, then blend.', 'How do you know ''zug'' isn''t a real word?', '{"default":{"words":["bim","cat","zug","mop"]},"ug":{"words":["bim","cat","zug","mop"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('PS2a_L4_A', 'PS2a', 4, 'A', 'Instructional Production', 'Paper, Pencil', 'Imagine you are teaching a younger child what a ''short a'' sound is. Explain it to them, and write down three example words to show them.', 'Child can articulate the sound and provides three accurate CVC words with short ''a''.', 'If they struggle to explain, ask them to make the sound first, then think of words that have it in the middle.', 'Why did you choose those three words to show the short ''a'' sound?', '{"default":{"target_vowel":"short a"},"ug":{"target_vowel":"short a"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('PS2a_L4_B', 'PS2a', 4, 'B', 'Creative Production', 'Paper, Pencil', 'Write the silliest sentence you can using as many short ''i'' CVC words as possible. Say the sentence out loud before you write it.', 'Child orally composes and then writes a sentence containing multiple short ''i'' words.', 'If they struggle, provide a starting word like ''The pig...''', 'Read your sentence to me. Which words have the short ''i'' sound?', '{"default":{"target_vowel":"short i"},"ug":{"target_vowel":"short i"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('PS2a_L4_C', 'PS2a', 4, 'C', 'Categorisation & Production', 'Paper, Pencil', 'Create two lists. At the top of one, write ''-at''. At the top of the other, write ''-in''. Now, write down as many words as you can think of that fit into these two families.', 'Child successfully generates at least 3-4 words for each word family.', 'If they get stuck, offer a starting sound: ''What if we put a /p/ sound in front of -at?''', 'What do all the words in the ''-at'' list have in common?', '{"default":{"families":["-at","-in"]},"ug":{"families":["-at","-in"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('PS2a_L4_M', 'PS2a', 4, 'M', 'Milestone Production', 'Paper, Pencil', 'We are going to write a short shopping list. I need a pen, a pan, and a mop. Say the items back to me, and then write the list.', 'Child accurately repeats the items and spells ''pen'', ''pan'', and ''mop'' correctly on the list.', 'Do not correct them during the task. If failed, return to Execute level tasks focusing on those specific vowel sounds.', 'Read your list back to me to make sure we have everything.', '{"default":{"list":["pen","pan","mop"]},"ug":{"list":["tin","pan","cup"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('PS2b_L1_A', 'PS2b', 1, 'A', 'Auditory Discrimination', 'None', 'Listen to the start of these two words: ''stop'' and ''sop''. In one of these words, I hear two consonant sounds pushed together at the beginning. Which word is it?', 'Child identifies ''stop'' and can isolate the /s/ and /t/ sounds.', 'If incorrect, exaggerate the sounds: /s/-/t/-op vs /s/-op.', 'What two sounds did you hear at the start of ''stop''?', '{"default":{"word_pairs":[["stop","sop"],["play","pay"],["fast","fat"]]},"ug":{"word_pairs":[["stop","sop"],["play","pay"],["fast","fat"]]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('PS2b_L1_B', 'PS2b', 1, 'B', 'Physical Manipulation', 'Two small objects (like stones or beads)', 'Place the two stones far apart. Say /s/ for one stone, and /p/ for the other. Now push the stones together quickly and say the sounds together: /sp/. What word starts with /sp/?', 'Child successfully blends the sounds and suggests a word like ''spot'' or ''spin''.', 'If they struggle, guide their hands to push the stones while you say the sounds with them.', 'How is /sp/ different from just /s/ or /p/?', '{"default":{"blends":["sp","cl","tr"]},"ug":{"blends":["sp","cl","tr"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('PS2b_L1_C', 'PS2b', 1, 'C', 'Verbal Identification', 'None', 'I''m going to say a word slowly: /f/ /l/ /a/ /g/. Can you push those sounds together and tell me the word?', 'Child says ''flag''.', 'If incorrect, say it a bit faster: /fl/ /ag/.', 'What two sounds do you hear at the very beginning of the word?', '{"default":{"words":["flag","crab","jump"]},"ug":{"words":["flag","crab","jump"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('PS2b_L2_A', 'PS2b', 2, 'A', 'Oral->Written Dictation', 'Paper, Pencil', 'I will say a word. You say the sounds, and then write it. The word is ''frog''. Make sure you hear all the sounds at the beginning.', 'Child says /f/ /r/ /o/ /g/ and writes ''frog''.', 'If they write ''fog'', ask: ''Read what you wrote. Does that say frog or fog?''', 'What two letters are making the beginning sounds?', '{"default":{"words":["frog","slip","tent"]},"ug":{"words":["frog","slip","tent"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('PS2b_L2_B', 'PS2b', 2, 'B', 'Oral->Written Word Manipulation', 'Paper, Pencil', 'Write the word ''lap''. Say it aloud. Now, put a ''c'' sound at the beginning. Say the new word, then write it.', 'Child writes ''lap'', says ''clap'', and writes ''clap''.', 'If incorrect, segment the sounds for them: /c/ /l/ /a/ /p/.', 'What happened to the word when we added the ''c''?', '{"default":{"transformations":[["lap","clap"],["pot","spot"]]},"ug":{"transformations":[["lap","clap"],["pot","spot"]]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('PS2b_L2_C', 'PS2b', 2, 'C', 'Oral->Written Sentence Dictation', 'Paper, Pencil', 'Repeat this sentence, then write it: ''The frog sat on the log.''', 'Child repeats and accurately spells ''frog'' including the blend.', 'If ''frog'' is misspelled, focus just on that word and have them stretch out the sounds.', 'Read the sentence. Does the word start with an ''f'' sound and an ''r'' sound?', '{"default":{"sentences":["The frog sat on the log.","The crab ran fast."]},"ug":{"sentences":["The frog sat on the log.","The crab ran fast."]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('PS2b_L3_A', 'PS2b', 3, 'A', 'Error Detection', 'Paper with printed sentence', 'Look at this sentence: ''I have a red s-l-e-d for the snow.'' Wait, that''s not right. It should say ''I have a red s-e-d for the snow.'' Or should it? Which word is correct?', 'Child identifies ''sled'' as the correct word.', 'If unsure, have them read both ''sled'' and ''sed'' and see which makes sense.', 'Why do we need the ''l'' in sled?', '{"default":{"words":["sled","sed"]},"ug":{"words":["drum","dum"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('PS2b_L3_B', 'PS2b', 3, 'B', 'Auditory Error Detection', 'None', 'Listen to this sentence: ''The baby will c-r-e-e-p on the floor.'' Now listen to this one: ''The baby will c-e-e-p on the floor.'' Which one sounds right?', 'Child identifies ''creep''.', 'If they miss the blend, repeat both words emphasizing the /r/.', 'What sound was missing in the second word?', '{"default":{"sentences":["The baby will creep on the floor.","The baby will ceep on the floor."]},"ug":{"sentences":["The baby will creep on the mat.","The baby will ceep on the mat."]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('PS2b_L3_C', 'PS2b', 3, 'C', 'Fill in the blank', 'Paper with printed words', 'Here is a word with a blank at the beginning: ''__op''. Should we put ''st'', ''fl'', or ''cr'' at the beginning to make it the word for what you do at a red light?', 'Child selects ''st'' to make ''stop''.', 'If they guess wrong, sound out the incorrect options with them: ''fl-op? cr-op?''', 'Why wouldn''t ''flop'' work for a red light?', '{"default":{"target":"stop","options":["st","fl","cr"],"clue":"red light"},"ug":{"target":"stop","options":["st","fl","cr"],"clue":"red light"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('PS2b_L4_A', 'PS2b', 4, 'A', 'Creative Production', 'Paper, Pencil', 'Write the blend ''pl'' at the top of your paper. Say the sound out loud. Now, write three real words that start with that blend.', 'Child accurately generates and writes three words starting with ''pl'' (e.g., play, plum, plan).', 'If they write words that just start with ''p'', remind them to make the /p/ /l/ sound together.', 'Read your words. Do they all start with the same two sounds?', '{"default":{"blend":"pl"},"ug":{"blend":"pl"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('PS2b_L4_B', 'PS2b', 4, 'B', 'Sentence Creation', 'Paper, Pencil', 'Think of an animal whose name starts with a blend, like a frog or a crab. Tell me a sentence about what that animal is doing, and then write it down.', 'Child orally composes and writes a sentence featuring an animal name with an initial blend.', 'If they choose an animal without a blend (like ''dog''), redirect them: ''Dog starts with one consonant sound. Can you think of one with two, like sn-ake?''', 'Which word in your sentence has a consonant blend?', '{"default":{"theme":"animals with blends"},"ug":{"theme":"animals with blends"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('PS2b_L4_C', 'PS2b', 4, 'C', 'Instructional Production', 'Paper, Pencil', 'Explain to me the difference between the word ''tap'' and the word ''trap''. What extra sound did we add, and where is it?', 'Child clearly explains that the /r/ sound was added after the /t/.', 'If they can''t explain, ask them to write both words and circle the difference.', 'How does adding that one letter change the meaning of the word?', '{"default":{"word_pair":["tap","trap"]},"ug":{"word_pair":["tap","trap"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('PS2b_L4_M', 'PS2b', 4, 'M', 'Milestone Production', 'Paper, Pencil', 'Look around the room or outside. Tell me one thing you see that has a consonant blend in its name (like a plant, a step, or the sky). Say it in a sentence, and then write the sentence.', 'Child successfully identifies an object with a blend, composes a sentence orally, and writes it accurately.', 'Do not correct during the task. If they fail to identify a blend or spell it correctly, review Execute level tasks.', 'Show me the word in your sentence that has the blend. What two sounds are pushed together?', '{"default":{"prompt":"Look around the room or outside."},"ug":{"prompt":"Look around the room or outside."}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('PS2c_L1_A', 'PS2c', 1, 'A', 'Auditory Discrimination', 'None', 'Listen to these words: ''ship'', ''shoe'', ''sun''. Two of these words start with a special sound made by two letters working together to make one new sound: /sh/. Which word does NOT start with the /sh/ sound?', 'Child identifies ''sun''.', 'If incorrect, emphasize the initial sounds: /sh/-ip, /sh/-oe, /s/-un.', 'What sound did ''sun'' start with? How is it different from the other two?', '{"default":{"words":["ship","shoe","sun"]},"ug":{"words":["shop","shoe","sun"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('PS2c_L1_B', 'PS2c', 1, 'B', 'Physical Manipulation', 'Letter tiles or cards: c, s, h, t', 'Put the ''s'' tile and the ''h'' tile together. When they stand next to each other, they don''t say /s/ /h/ anymore. They make a totally new sound: /sh/ (like telling someone to be quiet). Now put ''c'' and ''h'' together. They say /ch/ (like a train). Pick up the tiles that make the /sh/ sound.', 'Child selects ''sh''.', 'If wrong, repeat the sound association (quiet vs train).', 'Why do these two letters make only one sound now?', '{"default":{"digraphs":["sh","ch"]},"ug":{"digraphs":["sh","ch"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('PS2c_L1_C', 'PS2c', 1, 'C', 'Verbal Identification', 'None', 'I will say a word. If it starts with the /ch/ sound, say ''choo choo!''. If it doesn''t, just shake your head. Ready? ''Chip''.', 'Child responds appropriately (''choo choo!'').', 'If they miss it, exaggerate the /ch/ sound.', 'What sound did you hear at the beginning of ''chip''?', '{"default":{"words":[["chip",true],["cat",false],["chop",true]]},"ug":{"words":[["chop",true],["cup",false],["chin",true]]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('PS2c_L2_A', 'PS2c', 2, 'A', 'Oral->Written Dictation', 'Paper, Pencil', 'I am going to say a word. You say the sounds, and then write the letters. Remember, some sounds need two letters! The word is ''shop''.', 'Child says /sh/ /o/ /p/ and writes ''shop''.', 'If they write ''sop'', ask: ''Does your word say shop or sop?'' Remind them of the two letters needed for /sh/.', 'Which two letters work together to make the first sound in that word?', '{"default":{"words":["shop","chip","thin"]},"ug":{"words":["shop","chip","thin"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('PS2c_L2_B', 'PS2c', 2, 'B', 'Oral->Written Word Manipulation', 'Paper, Pencil', 'Write the word ''ship''. Say it loud. Now, change the /sh/ sound to a /ch/ sound. Say the new word, then write it.', 'Child writes ''ship'', says ''chip'', and writes ''chip''.', 'If incorrect, point to the ''sh'' and ask what it says, then ask what ''ch'' says.', 'What letters did you have to change to make the new word?', '{"default":{"ladders":[["ship","chip"],["thin","chin"]]},"ug":{"ladders":[["shop","chop"],["thin","chin"]]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('PS2c_L2_C', 'PS2c', 2, 'C', 'Oral->Written Sentence Dictation', 'Paper, Pencil', 'Listen to this sentence: ''The fish took a bath.'' Say it back to me, then write it down.', 'Child repeats and accurately spells ''fish'' (ending ''sh'') and ''bath'' (ending ''th'').', 'If digraphs are misspelled, isolate the word: ''What two letters make the /sh/ sound at the end of fish?''', 'Look at the end of the word ''bath''. What two letters are making the final sound?', '{"default":{"sentences":["The fish took a bath."]},"ug":{"sentences":["The fish took a bath."]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('PS2c_L3_A', 'PS2c', 3, 'A', 'Error Detection', 'Paper with printed sentence', 'Read this sentence carefully: ''The dog sat in the s-a-d-e.'' That doesn''t look right. What word should it be, and how do we spell the sound at the beginning?', 'Child identifies the word should be ''shade'' and that ''sh'' is missing.', 'If they read it as ''shade'', ask them to look at the letters again. ''Does s-a-d-e say shade?''', 'Why do we need an ''h'' after the ''s'' in this word?', '{"default":{"sentence":"The dog sat in the sade.","error":"sade","fix":"shade"},"ug":{"sentence":"The dog sat in the sade.","error":"sade","fix":"shade"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('PS2c_L3_B', 'PS2c', 3, 'B', 'Auditory Error Detection', 'None', 'Listen to this silly sentence: ''I need to s-o-p vegetables for dinner.'' Did I say that correctly?', 'Child identifies the error and corrects it to ''chop''.', 'If missed, repeat: ''Does s-o-p sound like what you do to vegetables?''', 'What two letters should be at the beginning of ''chop''?', '{"default":{"sentence":"I need to sop vegetables for dinner.","error":"sop","fix":"chop"},"ug":{"sentence":"I need to sop the cabbage for dinner.","error":"sop","fix":"chop"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('PS2c_L3_C', 'PS2c', 3, 'C', 'Fill in the blank', 'Paper with printed words', 'Here is a word: ''__ip''. We want it to be the word for a big boat. Should we put ''sh'', ''ch'', or ''th'' at the beginning?', 'Child selects ''sh'' to make ''ship''.', 'If incorrect, read the options aloud: ''chip? thip?''', 'Why wouldn''t ''ch'' work in this blank?', '{"default":{"target":"ship","options":["sh","ch","th"],"clue":"a big boat"},"ug":{"target":"ship","options":["sh","ch","th"],"clue":"a big boat on the lake"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('PS2c_L4_A', 'PS2c', 4, 'A', 'Instructional Production', 'Paper, Pencil', 'How would you explain the difference between a blend (like ''sl'') and a digraph (like ''sh'') to someone learning to read? Write down one example of each.', 'Child explains that a blend is two sounds pushed together, but a digraph is two letters making one completely new sound.', 'If they struggle, ask: ''In sl-, can you hear the s and the l? In sh-, can you hear the s and the h?''', 'Why is ''sh'' a digraph and not a blend?', '{"default":{"concept":"blend vs digraph"},"ug":{"concept":"blend vs digraph"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('PS2c_L4_B', 'PS2c', 4, 'B', 'Sentence Creation', 'Paper, Pencil', 'Think of a word that ends in ''th'', like ''math'' or ''bath''. Tell me a sentence using that word, and then write it down.', 'Child orally composes and writes a sentence using a word with a final ''th'' digraph.', 'If they pick a word starting with ''th'' (like ''the''), redirect them to find one that ends with it.', 'Point to the two letters that make the /th/ sound in your sentence.', '{"default":{"target":"ends in ''th''"},"ug":{"target":"ends in ''th''"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('PS2c_L4_C', 'PS2c', 4, 'C', 'Categorisation & Production', 'Paper, Pencil', 'Make two columns on your paper. Label one ''Starts with CH'' and the other ''Starts with SH''. Write two real words in each column. Say them aloud as you write them.', 'Child accurately generates two ''ch'' words and two ''sh'' words and places them in the correct columns.', 'If they struggle to think of words, offer clues (e.g., ''What do you do with an axe?'' -> chop).', 'How are the sounds in the first column different from the sounds in the second column?', '{"default":{"columns":["ch","sh"]},"ug":{"columns":["ch","sh"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('PS2c_L4_M', 'PS2c', 4, 'M', 'Milestone Production', 'Paper, Pencil', 'We need to leave a short note. Think of a short sentence telling someone to do something, using a word with ''sh'' or ''ch'' (like ''shut the door'' or ''chop the wood''). Say the sentence to me, then write the note.', 'Child correctly composes and writes a functional sentence utilizing a digraph.', 'Do not correct during the task. If spelling or concept fails, review Execute level tasks.', 'Read the note back to me. Did you use the two letters that work together to make one sound?', '{"default":{"examples":["shut the door","chop the wood"]},"ug":{"examples":["shut the door","chop the wood"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('PS2d_L1_A', 'PS2d', 1, 'A', 'Auditory Discrimination', 'None', 'Listen to the word ''mad''. Now listen to the word ''made''. How did the vowel sound in the middle change?', 'Child identifies that ''mad'' has a short /a/ and ''made'' has a long /a/ (saying its name).', 'If they struggle, say ''m-aaaa-d'' vs ''m-ayyyy-d'' slowly.', 'What is the difference between the vowel sound in mad and made?', '{"default":{"pairs":[["mad","made"],["hop","hope"],["sit","site"]]},"ug":{"pairs":[["tap","tape"],["not","note"],["bit","bite"]]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('PS2d_L1_B', 'PS2d', 1, 'B', 'Physical Manipulation', 'Paper, Pencil, A small stick or pencil to act as a ''magic wand''', 'Write ''tap''. Now, use your ''magic e'' wand (pencil) and point to the end of the word. The ''e'' tells the vowel to say its name. Say the new word.', 'Child touches the end of the word and says ''tape''.', 'If they say ''tap-e'', remind them the ''e'' is silent, it just does magic on the vowel.', 'What does the magic ''e'' tell the vowel to do?', '{"default":{"words":["tap","kit","rob"]},"ug":{"words":["tap","kit","not"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('PS2d_L1_C', 'PS2d', 1, 'C', 'Visual Discrimination', 'Paper with printed words', 'Look at these two words: ''ran'' and ''rain''. In the second word, the ''a'' and ''i'' are a team working together. The first one does the talking and says its name. What does ''rain'' say?', 'Child correctly reads ''rain''.', 'If they read ''ran-in'', explain the vowel team rule: ''When two vowels go walking, the first one does the talking.''', 'Which letter does the talking in ''ai''?', '{"default":{"words":[["ran","rain"],["met","meet"],["got","goat"]]},"ug":{"words":[["ran","rain"],["bed","bead"],["cot","coat"]]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('PS2d_L2_A', 'PS2d', 2, 'A', 'Oral->Written Dictation', 'Paper, Pencil', 'I am going to say a word that has a long vowel sound. You need a magic ''e'' at the end to make it happen. The word is ''cake''. Say it, stretch it, write it.', 'Child says /c/ /a/ /k/ and writes ''cake''.', 'If they write ''cak'', ask: ''Does this say cake or cak? What is missing?''', 'Why did you put an ''e'' at the end of the word?', '{"default":{"words":["cake","bike","home","cute"]},"ug":{"words":["cake","bite","hole","tube"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('PS2d_L2_B', 'PS2d', 2, 'B', 'Oral->Written Word Manipulation', 'Paper, Pencil', 'Write ''boat''. Now, change the first letter to make it say ''coat''. Say the new word, then write it. Remember the vowel team ''oa''.', 'Child writes ''boat'', says ''coat'', and writes ''coat''.', 'If they spell ''cote'', remind them we are using the vowel team ''oa'' for this list.', 'What two letters make the long /o/ sound in coat?', '{"default":{"words":[["boat","coat"],["rain","train"]]},"ug":{"words":[["boat","goat"],["rain","train"]]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('PS2d_L2_C', 'PS2d', 2, 'C', 'Oral->Written Sentence Dictation', 'Paper, Pencil', 'Listen to this sentence: ''Take the bike to the gate.'' Say it back to me, then write it down.', 'Child repeats the sentence and correctly spells ''take'', ''bike'', and ''gate'' using the magic ''e''.', 'If a word is spelled wrong, focus on the missing silent ''e''.', 'Look at the words take, bike, and gate. What do they all have at the end?', '{"default":{"sentences":["Take the bike to the gate."]},"ug":{"sentences":["Take the bike to the gate."]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('PS2d_L3_A', 'PS2d', 3, 'A', 'Error Detection', 'Paper with printed sentence', 'Read this sentence: ''I h-o-p to see you soon.'' Look at the word ''hop''. Should it be hop, or hope? How do we fix it?', 'Child identifies the error, says ''hope'', and adds an ''e''.', 'If they don''t see it, ask them to read the sentence literally. ''I hop to see you soon.''', 'Why does adding an ''e'' change hop into hope?', '{"default":{"sentence":"I hop to see you soon.","error":"hop","fix":"hope"},"ug":{"sentence":"I hop to see you soon.","error":"hop","fix":"hope"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('PS2d_L3_B', 'PS2d', 3, 'B', 'Auditory Error Detection', 'None', 'Listen to my sentence: ''The t-r-a-n is on the tracks.'' Did I pronounce that correctly for a big machine on tracks?', 'Child identifies the error and corrects it to ''train''.', 'If they agree, say: ''Tran? Or train?''', 'What sound did I miss in the middle of ''train''?', '{"default":{"sentence":"The t-r-a-n is on the tracks.","error":"tran","fix":"train"},"ug":{"sentence":"The b-o-t is on the lake.","error":"bot","fix":"boat"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('PS2d_L3_C', 'PS2d', 3, 'C', 'Visual Discrimination', 'Paper with printed words', 'Read these nonsense words and tell me if the vowel says its name (long) or not: ''plame'', ''snib'', ''foat'', ''drit''.', 'Child correctly identifies ''plame'' and ''foat'' as having long vowels based on their spelling patterns.', 'If incorrect, point out the ''e'' on ''plame'' and the ''oa'' in ''foat''.', 'How did you know ''plame'' has a long /a/ sound even though it''s not a real word?', '{"default":{"words":["plame","snib","foat","drit"]},"ug":{"words":["plame","snib","foat","drit"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('PS2d_L4_A', 'PS2d', 4, 'A', 'Instructional Production', 'Paper, Pencil', 'Teach someone younger the ''magic e'' rule. How does the ''e'' at the end change the vowel in the middle? Write down two words to prove it, showing the short version and the long version.', 'Child explains the rule accurately and provides examples like cap/cape, bit/bite.', 'If they struggle to explain, have them just do the example first.', 'Does the ''e'' make a sound itself?', '{"default":{"concept":"magic e"},"ug":{"concept":"magic e"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('PS2d_L4_B', 'PS2d', 4, 'B', 'Creative Production', 'Paper, Pencil', 'Write the vowel team ''ee'' at the top of your paper. Think of three words that use this team, say them out loud, and write them down.', 'Child correctly generates and spells three words with ''ee'' (e.g., tree, see, meet).', 'If they struggle, provide clues: ''What do you do with your eyes?''', 'What sound does the ''ee'' team make?', '{"default":{"vowel_team":"ee"},"ug":{"vowel_team":"ee"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('PS2d_L4_C', 'PS2d', 4, 'C', 'Sentence Creation', 'Paper, Pencil', 'Make up a short sentence that has at least two words with a magic ''e'' (like ''bike'' or ''gate''). Tell me the sentence, and then write it.', 'Child composes and writes a sentence utilizing at least two CVCe words.', 'If they can''t think of words, give them a list to choose from (make, time, nose, cute).', 'Read your sentence back. Point to the words with the magic ''e''.', '{"default":{"constraint":"two magic e words"},"ug":{"constraint":"two magic e words"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('PS2d_L4_M', 'PS2d', 4, 'M', 'Milestone Production', 'Paper, Pencil', 'We need to make a sign for a game. Think of a short rule that uses a long vowel word (like ''Wait here'' or ''Make a line''). Say your rule to me, then write the sign.', 'Child orally composes and accurately spells a phrase using a long vowel pattern.', 'Do not correct during the task. If spelling or concept fails, review Execute level tasks.', 'Show me the word in your sign that has a long vowel sound. How did you spell it?', '{"default":{"examples":["Wait here","Make a line"]},"ug":{"examples":["Wait here","Make a line"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('PS2e_L1_A', 'PS2e', 1, 'A', 'Auditory Discrimination', 'None', 'Listen to these words: ''cat'', ''car''. The ''r'' in ''car'' is bossy. It changes how the ''a'' sounds. Which word has the bossy ''r'' sound: ''mat'' or ''star''?', 'Child identifies ''star''.', 'If incorrect, exaggerate the sounds: /a/ vs /ar/.', 'What does the bossy ''r'' do to the vowel before it?', '{"default":{"words":[["mat","star"],["hen","her"],["sit","sir"]]},"ug":{"words":[["mat","star"],["pen","her"],["pit","sir"]]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('PS2e_L1_B', 'PS2e', 1, 'B', 'Verbal Identification', 'None', 'I will say a word. If it has the /ar/ sound like ''car'', say ''vroom!''. Ready? ''Farm''. ''Pat''. ''Dark''.', 'Child responds appropriately (''vroom'' for farm, dark).', 'If they miss one, isolate the sound.', 'What two letters make that /ar/ sound?', '{"default":{"words":[["farm",true],["pat",false],["dark",true]]},"ug":{"words":[["park",true],["pan",false],["dark",true]]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('PS2e_L1_C', 'PS2e', 1, 'C', 'Visual Discrimination', 'Paper with printed words', 'Look at these words: ''her'', ''bird'', ''fur''. They all sound exactly the same in the middle (/er/), but they are spelled differently. Which one uses ''i-r''?', 'Child points to ''bird''.', 'If they misread, explain that er, ir, and ur all make the same bossy ''r'' sound.', 'Even though they are spelled differently, what sound do they all make?', '{"default":{"words":["her","bird","fur"]},"ug":{"words":["her","bird","fur"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('PS2e_L2_A', 'PS2e', 2, 'A', 'Oral->Written Dictation', 'Paper, Pencil', 'I am going to say a word. You say the sounds, and then write the letters. The word is ''star''. Remember the bossy ''r''!', 'Child says /s/ /t/ /ar/ and writes ''star''.', 'If they write ''ster'' or ''star'', gently correct the spelling pattern.', 'Which two letters made the /ar/ sound?', '{"default":{"words":["star","fork","yard","horn"]},"ug":{"words":["star","fork","yard","horn"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('PS2e_L2_B', 'PS2e', 2, 'B', 'Oral->Written Word Manipulation', 'Paper, Pencil', 'Write the word ''cat''. Now, insert an ''r'' right after the ''a''. Say the new word, then write it.', 'Child writes ''cat'', says ''cart'', and writes ''cart''.', 'If they put the ''r'' at the end (''catr''), point to the spot after the ''a''.', 'How did the vowel sound change when we added the ''r''?', '{"default":{"words":[["cat","cart"],["hut","hurt"]]},"ug":{"words":[["pot","port"],["hut","hurt"]]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('PS2e_L2_C', 'PS2e', 2, 'C', 'Oral->Written Sentence Dictation', 'Paper, Pencil', 'Repeat this sentence, then write it: ''The bird sat on the car.''', 'Child repeats and spells ''bird'' (ir) and ''car'' (ar) correctly.', 'If they misspell ''bird'' as ''berd'' or ''burd'', tell them ''bird uses the i-r pattern.''', 'What letters make the bossy ''r'' sound in ''bird''?', '{"default":{"sentences":["The bird sat on the car."]},"ug":{"sentences":["The bird sat on the car."]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('PS2e_L3_A', 'PS2e', 3, 'A', 'Error Detection', 'Paper with printed sentence', 'Read this sentence: ''I want f-o-k with my dinner.'' Wait, that''s not how we spell the tool we eat with. What is missing?', 'Child identifies that ''fork'' needs an ''r''.', 'If they don''t see it, read it out loud exactly as written.', 'Why do we need the ''r'' in fork?', '{"default":{"sentence":"I want fok with my dinner.","error":"fok","fix":"fork"},"ug":{"sentence":"I want fok with my dinner.","error":"fok","fix":"fork"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('PS2e_L3_B', 'PS2e', 3, 'B', 'Auditory Error Detection', 'None', 'Listen to this: ''The dog began to b-a-c-k.'' Did I use the right word for the sound a dog makes?', 'Child identifies it should be ''bark''.', 'If they say yes, ask: ''Does a dog back or bark?''', 'What sound did I forget to say?', '{"default":{"sentence":"The dog began to b-a-c-k.","error":"back","fix":"bark"},"ug":{"sentence":"The dog began to b-a-c-k.","error":"back","fix":"bark"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('PS2e_L3_C', 'PS2e', 3, 'C', 'Visual Discrimination', 'Paper with printed words', 'Here are three ways someone tried to spell the word for a young girl: ''garl'', ''gerl'', ''girl''. Which one is the right spelling?', 'Child selects ''girl''.', 'If they choose ''gerl'', explain that ir, ur, and er sound the same, so we just have to memorize which one ''girl'' uses.', 'Why is it tricky to spell words with the /er/ sound?', '{"default":{"word":"girl","options":["garl","gerl","girl"]},"ug":{"word":"girl","options":["garl","gerl","girl"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('PS2e_L4_A', 'PS2e', 4, 'A', 'Creative Production', 'Paper, Pencil', 'Write ''ar'' at the top of your paper. Say the sound out loud. Now, write down three different words that have the ''ar'' sound in them.', 'Child successfully lists three words like car, far, star, park.', 'If they get stuck, give hints: ''Where do you play outside?''', 'Read your words. Do they all have the bossy ''r'' sound?', '{"default":{"sound":"ar"},"ug":{"sound":"ar"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('PS2e_L4_B', 'PS2e', 4, 'B', 'Sentence Creation', 'Paper, Pencil', 'Tell me a short sentence about an animal using a word that has ''or'' in it (like ''horse'' or ''horn''). Say the sentence, then write it.', 'Child orally composes and writes a sentence utilizing an ''or'' word.', 'If they pick an animal without ''or'', remind them of the rule.', 'Which word has the ''or'' sound?', '{"default":{"target":"or"},"ug":{"target":"or"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('PS2e_L4_C', 'PS2e', 4, 'C', 'Instructional Production', 'Paper, Pencil', 'Explain to me what ''bossy r'' means. What does the ''r'' do to the vowel that comes right before it? Give me one example.', 'Child explains that the ''r'' changes the vowel''s normal sound and provides a correct example.', 'If they can''t explain, have them write ''cat'' and ''cart'' and explain the difference.', 'Why do we call it bossy?', '{"default":{"concept":"bossy r"},"ug":{"concept":"bossy r"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('PS2e_L4_M', 'PS2e', 4, 'M', 'Milestone Production', 'Paper, Pencil', 'We are going to make a short list of things outside. Think of two things you might see outside that have the bossy ''r'' sound (like a car, a bird, or dirt). Say them to me, and then write them down.', 'Child accurately identifies and spells two bossy ''r'' words based on observation or recall.', 'Do not correct during the task. If spelling or concept fails, review Execute level tasks.', 'Point to the letters in your words that are making the bossy ''r'' sound.', '{"default":{"examples":["car","bird","dirt"]},"ug":{"examples":["car","bird","dirt"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('PS2f_L1_A', 'PS2f', 1, 'A', 'Auditory Discrimination', 'None', 'Listen to the word ''basket''. Let''s clap the parts we hear: bas-ket. How many claps was that?', 'Child identifies 2 syllables/claps.', 'If they clap once or three times, model it again slowly.', 'How many vowel sounds do you hear in ''basket''?', '{"default":{"words":[["basket",2],["cat",1],["banana",3]]},"ug":{"words":[["basket",2],["cup",1],["matooke",3]]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('PS2f_L1_B', 'PS2f', 1, 'B', 'Physical Manipulation', 'Paper, Scissors (or pencil to draw a line)', 'Write the word ''muffin'' big on a piece of paper. Say it loud: muf-fin. Where do you hear the split? Use the scissors (or pencil) to cut the word right between the two syllables.', 'Child cuts or draws a line between ''muf'' and ''fin'' (between the double consonants).', 'If they split it wrong, clap the syllables while looking at the word.', 'Why did you split it right between the two ''f''s?', '{"default":{"word":"muffin"},"ug":{"word":"cotton"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('PS2f_L1_C', 'PS2f', 1, 'C', 'Visual Discrimination', 'Paper with printed words', 'Look at the word ''hi''. The vowel is at the very end, so it''s ''open'' and says its name. Look at ''him''. The ''m'' closes the door, so the vowel is short. Which one has a closed door: ''me'' or ''met''?', 'Child identifies ''met'' as having a closed door (consonant at the end).', 'If wrong, explain the ''door'' analogy again.', 'What letter closes the door in ''met''?', '{"default":{"pairs":[["me","met"],["no","not"]]},"ug":{"pairs":[["me","met"],["no","not"]]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('PS2f_L2_A', 'PS2f', 2, 'A', 'Oral->Written Dictation', 'Paper, Pencil', 'I am going to say a long word, but we will write it one chunk at a time. The word is ''sunset''. First, say ''sun'' and write it. Now say ''set'' and write it right next to it.', 'Child writes ''sunset'' accurately by dividing it orally.', 'If they miss letters, have them sound out each chunk separately.', 'How does breaking a big word into chunks make it easier to spell?', '{"default":{"words":["sunset","picnic","napkin"]},"ug":{"words":["sunset","picnic","dustbin"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('PS2f_L2_B', 'PS2f', 2, 'B', 'Visual Manipulation & Encoding', 'Paper, Pencil', 'Write the word ''rabbit''. Now, draw a line to split it into two syllables. Read the first part, then the second part.', 'Child writes ''rabbit'' and draws a line between the b''s (rab/bit).', 'If they split it ra/bbit, remind them to split between double consonants.', 'What happens when we have two consonants between vowels? Where do we split it?', '{"default":{"words":["rabbit","kitten","sudden"]},"ug":{"words":["rabbit","kitten","sudden"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('PS2f_L2_C', 'PS2f', 2, 'C', 'Oral->Written Word Manipulation', 'Paper, Pencil', 'Write the word ''go''. Say it. Now, add a ''t'' to the end to close the door. What is the new word? Write it.', 'Child writes ''go'', says ''got'', and writes ''got''.', 'If they say ''goat'', remind them that closing the door makes the vowel short.', 'How did the sound of the ''o'' change when we closed the door?', '{"default":{"words":[["go","got"],["be","bed"]]},"ug":{"words":[["so","sop"],["he","hen"]]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('PS2f_L3_A', 'PS2f', 3, 'A', 'Error Detection', 'Paper with printed words', 'Someone tried to split the word ''basket'' into syllables. They wrote ''ba-sket''. Is that where the word splits?', 'Child identifies that it should be ''bas-ket''.', 'If they agree with ''ba-sket'', clap it out loud: bas-ket.', 'Why do we split between the ''s'' and the ''k''?', '{"default":{"word":"basket","error":"ba-sket","fix":"bas-ket"},"ug":{"word":"market","error":"ma-rket","fix":"mar-ket"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('PS2f_L3_B', 'PS2f', 3, 'B', 'Auditory Error Detection', 'None', 'I''m going to clap the syllables in the word ''butterfly''. *clap twice*. Did I get it right?', 'Child says no and correctly claps three times.', 'If they miss it, say ''but-ter-fly'' slowly while counting on fingers.', 'How many parts does the word ''butterfly'' have?', '{"default":{"word":"butterfly","error":2,"fix":3},"ug":{"word":"pineapple","error":2,"fix":3}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('PS2f_L3_C', 'PS2f', 3, 'C', 'Visual Discrimination', 'Paper with printed words', 'Look at these two words: ''robot'' and ''rabbit''. Which word has an open first syllable (where the vowel says its name)?', 'Child selects ''robot'' (ro-bot).', 'If they choose ''rabbit'' (rab-bit), remind them that the ''b'' closes the door on the ''a''.', 'Why does the ''o'' in robot say its name?', '{"default":{"options":["robot","rabbit"]},"ug":{"options":["robot","rabbit"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('PS2f_L4_A', 'PS2f', 4, 'A', 'Creative Production', 'Paper, Pencil', 'Think of three words that have exactly two syllables. Say them out loud, clap them to check, and then write them down.', 'Child successfully lists three 2-syllable words.', 'If they pick 1-syllable words, remind them they need to clap twice.', 'Read your words and clap as you read them.', '{"default":{"constraint":"two syllables"},"ug":{"constraint":"two syllables"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('PS2f_L4_B', 'PS2f', 4, 'B', 'Instructional Production', 'Paper, Pencil', 'Explain to me the difference between an open syllable (like ''no'') and a closed syllable (like ''not''). Write the two words down to help you explain.', 'Child accurately explains the concept of the consonant ''closing the door'' and changing the vowel sound.', 'If they struggle, ask: ''Which one has a vowel that says its name?''', 'What happens to the vowel sound when we close the syllable?', '{"default":{"concept":"open vs closed syllables"},"ug":{"concept":"open vs closed syllables"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('PS2f_L4_C', 'PS2f', 4, 'C', 'Creative Spelling', 'Paper, Pencil', 'Invent a silly, long alien name that has three syllables. Clap the syllables to me, and then write the name down spelling each chunk the way it sounds.', 'Child claps 3 syllables and writes a phonetically plausible string of letters (e.g., Zib-lok-nam).', 'If they just write random letters, have them do one syllable at a time.', 'Show me the three chunks you wrote. What vowels are in each chunk?', '{"default":{"theme":"alien name"},"ug":{"theme":"alien name"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('PS2f_L4_M', 'PS2f', 4, 'M', 'Milestone Production', 'Paper, Pencil', 'We are making a list of things to pack for a trip. Write down ''blanket'' and ''jacket''. Think about how many syllables are in each word to help you spell them.', 'Child writes ''blanket'' and ''jacket'' accurately, utilizing syllable division strategies if needed.', 'Do not correct during the task. If spelling fails heavily, review Execute level tasks.', 'How did breaking the word into chunks help you spell it?', '{"default":{"words":["blanket","jacket"]},"ug":{"words":["blanket","jacket"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('PS2g_L1_A', 'PS2g', 1, 'A', 'Auditory Discrimination', 'None', 'Listen to these words: ''light'', ''night'', ''right''. They all rhyme. What sound do you hear at the end of all of them?', 'Child identifies the /ite/ sound.', 'If they just say /t/, encourage them to listen to the whole chunk.', 'What other word rhymes with light and night?', '{"default":{"words":["light","night","right"]},"ug":{"words":["light","night","right"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('PS2g_L1_B', 'PS2g', 1, 'B', 'Visual Discrimination', 'A book or printed text', 'Look at this page. The letters ''i-g-h-t'' work together to make the /ite/ sound. Find a word on this page that has that pattern.', 'Child locates a word with the -ight pattern.', 'If they can''t find it, point out a few words and ask if they have the pattern.', 'What do those four letters say when they are together?', '{"default":{"pattern":"ight"},"ug":{"pattern":"ight"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('PS2g_L1_C', 'PS2g', 1, 'C', 'Physical Manipulation', 'Letter tiles: h, o, p, p, i, n, g', 'Here is the word ''hop''. We want to make it ''hopping''. If we just add ''ing'', the ''i'' makes the ''o'' long, and it says ''hoping''. We need an extra ''p'' to act like a wall to protect the short ''o''. Put the extra ''p'' in.', 'Child physically places the second ''p'' before the ''ing''.', 'If they don''t understand, demonstrate with and without the extra ''p''.', 'Why did we need two ''p''s in hopping?', '{"default":{"word":"hopping"},"ug":{"word":"hopping"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('PS2g_L2_A', 'PS2g', 2, 'A', 'Oral->Written Dictation', 'Paper, Pencil', 'The letters i-g-h-t say /ite/. I am going to say a word. You say it, then write it. The word is ''might''.', 'Child writes ''might'' accurately.', 'If they write ''mite'', remind them we are practicing the 4-letter pattern today.', 'Which four letters make the /ite/ sound in this word?', '{"default":{"words":["might","high","bright"]},"ug":{"words":["might","high","bright"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('PS2g_L2_B', 'PS2g', 2, 'B', 'Oral->Written Word Manipulation', 'Paper, Pencil', 'Write the word ''run''. Say it loud. Now, we want to write ''running''. Remember, ''run'' has a short vowel, so we must double the consonant before adding ''ing''. Write ''running''.', 'Child writes ''run'', says ''running'', and writes ''running'' with a double ''n''.', 'If they write ''runing'', ask: ''Did you build the wall to protect the short u?''', 'Why did we need two ''n''s?', '{"default":{"words":[["run","running"],["sit","sitting"]]},"ug":{"words":[["run","running"],["sit","sitting"]]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('PS2g_L2_C', 'PS2g', 2, 'C', 'Oral->Written Sentence Dictation', 'Paper, Pencil', 'Listen to this sentence: ''Turn on the bright light.'' Say it back to me, then write it.', 'Child repeats and spells ''bright'' and ''light'' using the -ight pattern.', 'If misspelled, isolate the word and ask what 4 letters make that sound.', 'What spelling pattern do bright and light share?', '{"default":{"sentences":["Turn on the bright light."]},"ug":{"sentences":["Turn on the bright light."]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('PS2g_L3_A', 'PS2g', 3, 'A', 'Error Detection', 'Paper with printed sentence', 'Read this: ''We look at the stars at n-i-t-e.'' Is that the standard way to spell the word ''night''?', 'Child identifies it should be spelled ''night''.', 'If they think ''nite'' is fine, explain that while people sometimes write it that way, the correct pattern is i-g-h-t.', 'What four letters should make the /ite/ sound in night?', '{"default":{"sentence":"We look at the stars at nite.","error":"nite","fix":"night"},"ug":{"sentence":"We look at the stars at nite.","error":"nite","fix":"night"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('PS2g_L3_B', 'PS2g', 3, 'B', 'Visual Discrimination', 'Paper with printed words', 'Look at these two words: ''hoping'' and ''hopping''. Which one means you are jumping up and down on one foot?', 'Child selects ''hopping''.', 'If they choose ''hoping'', review the short vowel vs long vowel doubling rule.', 'What does the word ''hoping'' mean?', '{"default":{"options":["hoping","hopping"],"target":"jumping"},"ug":{"options":["hoping","hopping"],"target":"jumping"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('PS2g_L3_C', 'PS2g', 3, 'C', 'Auditory Error Detection', 'None', 'If I want to write the word ''cutting'', do I need two ''t''s in the middle, or just one? Listen to the vowel sound in ''cut''.', 'Child states two ''t''s are needed.', 'If they say one, ask: ''Is the u in cut short or long? If it''s short, we need to protect it with two consonants.''', 'Why do we need two ''t''s for cutting?', '{"default":{"word":"cutting"},"ug":{"word":"cutting"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('PS2g_L4_A', 'PS2g', 4, 'A', 'Creative Production', 'Paper, Pencil', 'Write ''-ight'' at the top of your paper. Write three words that rhyme with ''light'' using that pattern.', 'Child accurately lists three -ight words.', 'If stuck, offer initial sounds (f, m, s).', 'Read your words. Do they all rhyme?', '{"default":{"pattern":"ight"},"ug":{"pattern":"ight"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('PS2g_L4_B', 'PS2g', 4, 'B', 'Instructional Production', 'Paper, Pencil', 'Explain to me the rule for adding ''-ing'' to a word like ''sit''. What do you have to do before you add the ''-ing''? Write the word down to show me.', 'Child explains that the ''t'' must be doubled, and writes ''sitting''.', 'If they can''t explain it, prompt them: ''What happens if we don''t add the second t?''', 'Why do we double the last letter?', '{"default":{"concept":"doubling rule"},"ug":{"concept":"doubling rule"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('PS2g_L4_C', 'PS2g', 4, 'C', 'Sentence Creation', 'Paper, Pencil', 'Make up a sentence using the word ''swimming''. Think carefully about the spelling rule before you write it down.', 'Child composes and accurately spells a sentence containing ''swimming'' (double m).', 'If they write ''swiming'', ask them to review the doubling rule.', 'How did you spell swimming? Why did you spell it that way?', '{"default":{"target":"swimming"},"ug":{"target":"swimming"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('PS2g_L4_M', 'PS2g', 4, 'M', 'Milestone Production', 'Paper, Pencil', 'Write a short sentence about something you like doing (like ''running'' or ''reading''). Think carefully about whether you need to double any letters before adding ''-ing''. Say the sentence to me, then write it.', 'Child composes a sentence and accurately applies or avoids the doubling rule when adding -ing to their chosen verb.', 'Do not correct during the task. If spelling fails, review Execute level tasks.', 'Show me the word ending in ''-ing''. Did you double the consonant? Why or why not?', '{"default":{"examples":["running","reading"]},"ug":{"examples":["running","reading"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('PS2h_L1_A', 'PS2h', 1, 'A', 'Auditory Discrimination', 'None', 'Listen to the word ''happy''. Now listen to ''unhappy''. What little chunk of sound did I add to the beginning of the second word?', 'Child identifies ''un''.', 'If they don''t catch it, say ''un-happy''.', 'What does ''un'' mean when we put it in front of happy?', '{"default":{"words":["happy","unhappy"]},"ug":{"words":["happy","unhappy"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('PS2h_L1_B', 'PS2h', 1, 'B', 'Physical Manipulation', 'Three small pieces of paper with ''un'', ''do'', and ''ing'' written on them', 'The middle paper says ''do''. That is the root word. If we put ''un'' in front of it, what does it say? If we take ''un'' away and put ''ing'' at the end, what does it say?', 'Child physically moves the papers and reads ''undo'' and ''doing''.', 'If they misread, point to each part: un + do.', 'How does the meaning of ''do'' change when we add ''un''?', '{"default":{"root":"do","affixes":["un","ing"]},"ug":{"root":"do","affixes":["un","ing"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('PS2h_L1_C', 'PS2h', 1, 'C', 'Visual Discrimination', 'Paper with printed words', 'Look at these words: ''help'', ''helpful'', ''helpless''. They all share the same root word. Circle the root word ''help'' hidden inside the two longer words.', 'Child successfully circles ''help'' inside ''helpful'' and ''helpless''.', 'If they circle the whole word, show them how to cover up the ending to see the root.', 'What does the ending ''-ful'' mean? What does ''-less'' mean?', '{"default":{"words":["help","helpful","helpless"]},"ug":{"words":["help","helpful","helpless"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('PS2h_L2_A', 'PS2h', 2, 'A', 'Oral->Written Dictation', 'Paper, Pencil', 'I will say a word with a prefix. Think of the root word first, then add the prefix chunk. The word is ''rebuild''. Say it, then write it.', 'Child writes ''rebuild'' accurately.', 'If misspelled, isolate the chunks: ''How do you spell the prefix re-? How do you spell the root build?''', 'What does the prefix ''re-'' mean in the word rebuild?', '{"default":{"words":["rebuild","unlock","remake"]},"ug":{"words":["rebuild","unlock","remake"]}}', 0);